--CREATE MASTER KEY ENCRYPTION BY PASSWORD = '{password}';
--CREATE DATABASE SCOPED CREDENTIAL mokshadmin WITH IDENTITY = 'Managed Identity';


CREATE EXTERNAL FILE FORMAT extfileformat WITH (
    FORMAT_TYPE = PARQUET,
    DATA_COMPRESSION = 'org.apache.hadoop.io.compress.SnappyCodec'
);
GO

CREATE EXTERNAL DATA SOURCE goldlayer WITH (
    LOCATION = 'https://olistecommstorageaccount.dfs.core.windows.net/olist-ecomm-data/gold/',
    CREDENTIAL = mokshadmin
);
GO

CREATE EXTERNAL TABLE gold.final_table WITH (
    LOCATION = 'final_table',
    DATA_SOURCE = goldlayer,
    FILE_FORMAT = extfileformat
) AS SELECT * FROM gold.final;
GO

CREATE EXTERNAL TABLE gold.delivered_orders_table WITH (
    LOCATION = 'delivered_orders',
    DATA_SOURCE = goldlayer,
    FILE_FORMAT = extfileformat
) AS SELECT * FROM gold.delivered_orders;
GO

CREATE EXTERNAL TABLE gold.category_sales_table WITH (
    LOCATION = 'category_sales',
    DATA_SOURCE = goldlayer,
    FILE_FORMAT = extfileformat
) AS SELECT * FROM gold.category_sales;
GO

CREATE EXTERNAL TABLE gold.monthly_sales_table WITH (
    LOCATION = 'monthly_sales',
    DATA_SOURCE = goldlayer,
    FILE_FORMAT = extfileformat
) AS SELECT * FROM gold.monthly_sales;
GO

CREATE EXTERNAL TABLE gold.delivery_performance_table WITH (
    LOCATION = 'delivery_performance_by_state',
    DATA_SOURCE = goldlayer,
    FILE_FORMAT = extfileformat
) AS SELECT * FROM gold.delivery_performance_by_state;
GO

CREATE EXTERNAL TABLE gold.seller_performance_table WITH (
    LOCATION = 'seller_performance',
    DATA_SOURCE = goldlayer,
    FILE_FORMAT = extfileformat
) AS SELECT * FROM gold.seller_performance;
GO
